#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *data;
    int front;
    int back;
    int cap;
} Deque;

Deque* newDeque(int cap) {
    Deque *dq = (Deque*)malloc(sizeof(Deque));
    dq->data = (int*)malloc(sizeof(int)*cap);
    dq->front = dq->back = 0;
    dq->cap = cap;
    return dq;
}

int empty(Deque *dq) { return dq->front == dq->back; }
int front(Deque *dq) { return dq->data[dq->front]; }
int back(Deque *dq) { return dq->data[(dq->back-1+ dq->cap)%dq->cap]; }
void pushBack(Deque *dq, int val) { dq->data[dq->back] = val; dq->back = (dq->back+1)%dq->cap; }
void popFront(Deque *dq) { dq->front = (dq->front+1)%dq->cap; }
void popBack(Deque *dq) { dq->back = (dq->back-1+dq->cap)%dq->cap; }

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,W; scanf("%d %d", &N, &W);
        int *H = (int*)malloc(sizeof(int)*N);
        for(int i=0;i<N;i++) scanf("%d", &H[i]);
        Deque *dqMin = newDeque(N+5), *dqMax = newDeque(N+5);
        long long ans = 0;
        for(int i=0;i<N;i++){
            // maintain min deque (increasing)
            while(!empty(dqMin) && H[back(dqMin)] >= H[i]) popBack(dqMin);
            pushBack(dqMin, i);
            // maintain max deque (decreasing)
            while(!empty(dqMax) && H[back(dqMax)] <= H[i]) popBack(dqMax);
            pushBack(dqMax, i);
            // remove out of window
            if(i>=W){
                if(front(dqMin) <= i-W) popFront(dqMin);
                if(front(dqMax) <= i-W) popFront(dqMax);
            }
            if(i>=W-1){
                int curMin = H[front(dqMin)];
                int curMax = H[front(dqMax)];
                if(curMax - curMin == W-1) ans++;
            }
        }
        printf("%lld\n", ans);
        free(H);
        free(dqMin->data); free(dqMin);
        free(dqMax->data); free(dqMax);
    }
    return 0;
}

