import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int W = fs.nextInt();
            int[] H = new int[N];
            for (int i = 0; i < N; i++) H[i] = fs.nextInt();
            Deque<Integer> dqMin = new ArrayDeque<>();
            Deque<Integer> dqMax = new ArrayDeque<>();
            long ans = 0;
            for (int i = 0; i < N; i++) {
                while (!dqMin.isEmpty() && H[dqMin.peekLast()] >= H[i]) dqMin.pollLast();
                dqMin.addLast(i);
                while (!dqMax.isEmpty() && H[dqMax.peekLast()] <= H[i]) dqMax.pollLast();
                dqMax.addLast(i);
                if (i >= W) {
                    if (dqMin.peekFirst() <= i - W) dqMin.pollFirst();
                    if (dqMax.peekFirst() <= i - W) dqMax.pollFirst();
                }
                if (i >= W - 1) {
                    int curMin = H[dqMin.peekFirst()];
                    int curMax = H[dqMax.peekFirst()];
                    if (curMax - curMin == W - 1) ans++;
                }
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
    }
}

