import sys
from collections import deque

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); W = next(it)
        H = [next(it) for _ in range(N)]
        dq_min = deque()
        dq_max = deque()
        ans = 0
        for i, val in enumerate(H):
            while dq_min and H[dq_min[-1]] >= val:
                dq_min.pop()
            dq_min.append(i)
            while dq_max and H[dq_max[-1]] <= val:
                dq_max.pop()
            dq_max.append(i)
            if i >= W:
                if dq_min[0] <= i - W:
                    dq_min.popleft()
                if dq_max[0] <= i - W:
                    dq_max.popleft()
            if i >= W - 1:
                cur_min = H[dq_min[0]]
                cur_max = H[dq_max[0]]
                if cur_max - cur_min == W - 1:
                    ans += 1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

