const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = data[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = data[idx++];
  const W = data[idx++];
  const H = data.slice(idx, idx + N);
  idx += N;
  const dqMin = [];
  const dqMax = [];
  let ans = 0;
  const push = (dq, i, comp) => {
    while (dq.length && comp(H[dq[dq.length - 1]], H[i])) dq.pop();
    dq.push(i);
  };
  const popOut = (dq, limit) => {
    if (dq.length && dq[0] <= limit) dq.shift();
  };
  for (let i = 0; i < N; i++) {
    push(dqMin, i, (a, b) => a >= b); // increasing
    push(dqMax, i, (a, b) => a <= b); // decreasing
    if (i >= W) {
      popOut(dqMin, i - W);
      popOut(dqMax, i - W);
    }
    if (i >= W - 1) {
      const curMin = H[dqMin[0]];
      const curMax = H[dqMax[0]];
      if (curMax - curMin === W - 1) ans++;
    }
  }
  outputs.push(String(ans));
}
